-- Get claim and user IDs
SET @claim1_id = (SELECT id FROM claims WHERE claim_number = 'CLM-2024-001');
SET @claim3_id = (SELECT id FROM claims WHERE claim_number = 'CLM-2024-003');
SET @claim5_id = (SELECT id FROM claims WHERE claim_number = 'CLM-2024-005');
SET @assessor_id = (SELECT id FROM users WHERE role = 'assessor' LIMIT 1);

-- Insert AI assessments
INSERT INTO ai_assessments (claim_id, total_cost, labor_cost, parts_cost, repair_duration, damage_assessment, fraud_risk, recommendations, created_at) VALUES
(@claim1_id, 15000, 6000, 9000, 5, 'Moderate rear-end damage. Bumper replacement required, trunk lid needs panel beating and repainting. Both tail light assemblies damaged. Structural integrity appears intact.', 'low', 'Recommend full bumper replacement rather than repair. Check for hidden frame damage during disassembly.', NOW()),
(@claim3_id, 28000, 12000, 16000, 8, 'Significant front-end damage. Hood, bumper, and both headlights require replacement. Radiator shows signs of impact damage. Front grille and crash bar damaged.', 'medium', 'Inspect cooling system thoroughly. Check for airbag sensor damage. Recommend alignment check after repairs.', NOW()),
(@claim5_id, 22000, 14000, 8000, 10, 'Extensive hail damage across all horizontal surfaces. Approximately 45 dents requiring paintless dent removal. Windshield replacement necessary due to crack.', 'low', 'PDR (Paintless Dent Removal) recommended for most dents. Full windshield replacement required. No structural damage detected.', NOW());

-- Insert assessor evaluations
INSERT INTO assessor_evaluations (claim_id, assessor_id, total_cost, labor_cost, parts_cost, repair_duration, damage_assessment, fraud_risk, recommendations, created_at) VALUES
(@claim1_id, @assessor_id, 14500, 5800, 8700, 5, 'Confirmed rear-end damage assessment. Bumper replacement and trunk lid repair required. Tail lights both damaged beyond repair.', 'low', 'Agree with AI assessment. No signs of pre-existing damage or fraud.', NOW()),
(@claim3_id, @assessor_id, 26500, 11000, 15500, 7, 'Front-end damage confirmed. Radiator damage less severe than AI estimated. Hood and bumper require replacement.', 'low', 'Radiator can be repaired rather than replaced, reducing costs. Otherwise agree with AI assessment.', NOW());

-- Insert panel beater quotes for BMW claim (comparison scenario)
INSERT INTO panel_beater_quotes (claim_id, panel_beater_id, total_cost, labor_cost, parts_cost, repair_duration, itemized_breakdown, notes, created_at) VALUES
(@claim3_id, 1, 27500, 11500, 16000, 8, '[{"item":"Front bumper replacement","cost":4500},{"item":"Hood replacement","cost":6000},{"item":"Headlight assemblies (both)","cost":3500},{"item":"Radiator replacement","cost":2000},{"item":"Labor - disassembly and reassembly","cost":7000},{"item":"Paint and finishing","cost":4500}]', 'Premium OEM parts used. Includes full warranty on parts and labor.', NOW()),
(@claim3_id, 3, 31000, 13000, 18000, 9, '[{"item":"Front bumper replacement (OEM)","cost":5500},{"item":"Hood replacement (OEM)","cost":7000},{"item":"Headlight assemblies (OEM)","cost":4000},{"item":"Radiator replacement","cost":1500},{"item":"Labor - disassembly and reassembly","cost":8000},{"item":"Paint and finishing (premium)","cost":5000}]', 'All genuine BMW parts. Extended warranty included. Specialized BMW technicians.', NOW()),
(@claim3_id, 5, 42000, 18000, 24000, 12, '[{"item":"Front bumper replacement","cost":8000},{"item":"Hood replacement","cost":9000},{"item":"Headlight assemblies","cost":5000},{"item":"Radiator and cooling system","cost":2000},{"item":"Labor - extensive repairs","cost":12000},{"item":"Paint and finishing","cost":6000}]', 'Comprehensive repair with additional reinforcement work recommended.', NOW());

